sql:
SELECT COUNT(DISTINCT address_id) AS address_count
FROM addresses
WHERE country = 'United States' AND state = 'California';

external_knowledge:
- 'entities' refers to both individuals and companies;
- 'contact details' include email and phone number;
- 'key business data' encompasses the type of company, annual revenue, and the number of employees;
- 'where they're located' refers to their address, which includes their street, city, state, and country.

sql:
SELECT contact_id, contact_type, department, email, phone 
FROM contacts 
WHERE company_id IN (SELECT entity_id FROM entities WHERE related_company_id = 1);

SELECT name, email
FROM entities
WHERE is_company = 1 AND related_company_id IS NOT NULL;
